 565→export function parseSendMailResult(r: PacketReader): SendMailResultPacket {
 566→  return {
 567→    mailId: r.uint32LE(),
 568→    action: r.uint32LE(),
 569→    result: r.uint32LE(),
 570→  };
 571→}
