 621→export function formatMailResultError(result: number): string | undefined {
 622→  switch (result) {
 623→    case MailResult.OK:
 624→      return undefined;
 625→    case MailResult.ERR_CANNOT_SEND_TO_SELF:
 626→      return "Cannot send mail to yourself.";
 627→    case MailResult.ERR_NOT_ENOUGH_MONEY:
