 629→    case MailResult.ERR_RECIPIENT_NOT_FOUND:
 630→      return "Player not found.";
 631→    case MailResult.ERR_NOT_YOUR_TEAM:
 632→      return "Cannot send mail to the opposite faction.";
 633→    case MailResult.ERR_INTERNAL_ERROR:
 634→      return "Internal mail error.";
 635→    case MailResult.ERR_DISABLED_FOR_TRIAL_ACC:
 636→      return "Trial accounts cannot send mail.";
 637→    case MailResult.ERR_RECIPIENT_CAP_REACHED:
 638→      return "Recipient's mailbox is full.";
 639→    case MailResult.ERR_MAIL_AND_CHAT_SUSPENDED:
 640→      return "Mail is suspended on this account.";
 641→    case MailResult.ERR_TOO_MANY_ATTACHMENTS:
 642→      return "Too many attachments.";
 643→    default:
 644→      return `Mail error (code ${result}).`;
 645→  }
