1052→function formatMailAge(days: number): string {
1053→  if (days < 1 / 24) return "< 1m";
1054→  if (days < 1) {
1055→    const hours = Math.floor(days * 24);
1056→    return `${hours}h`;
1057→  }
1058→  const d = Math.floor(days);
1059→  return `${d}d`;
1060→}
1061→
1062→function senderLabel(entry: MailEntry): string {
1063→  if (entry.messageType === MailMessageType.AUCTION) return "Auction House";
1064→  if (entry.messageType === MailMessageType.CREATURE) return "NPC";
1065→  if (entry.messageType === MailMessageType.GAMEOBJECT) return "System";
1066→  if (entry.messageType === MailMessageType.CALENDAR) return "Calendar";
1067→  return "";
1068→}
1069→
1070→export function formatMailList(
1071→  entries: MailEntry[],
1072→  nameCache: Map<number, string>,
1073→): string {
1074→  if (entries.length === 0) return "[mail] Mailbox is empty";
1075→  const lines: string[] = [`=== Mailbox (${entries.length} messages) ===`];
1076→  for (let i = 0; i < entries.length; i++) {
1077→    const e = entries[i]!;
1078→    const unread = !(e.flags & MailCheckMask.READ);
1079→    const marker = unread ? "*" : " ";
1080→    const idx = `#${i + 1}`;
1081→    let sender = senderLabel(e);
1082→    if (!sender && e.senderGuid !== undefined) {
1083→      const guidLow = Number(e.senderGuid & 0xffffffffn);
1084→      sender = nameCache.get(guidLow) ?? `Player`;
1085→    }
1086→    const subj =
1087→      e.subject.length > 30 ? e.subject.slice(0, 27) + "..." : e.subject;
1088→    const age = formatMailAge(e.expirationDays);
1089→    lines.push(`${marker}${idx.padEnd(4)} ${sender.padEnd(15)} ${subj.padEnd(32)} ${age}`);
1090→  }
1091→  return lines.join("\n");
1092→}
1093→
1094→export function formatMailListJson(entries: MailEntry[]): string {
1095→  return JSON.stringify({
1096→    type: "MAIL_LIST",
1097→    count: entries.length,
1098→    mails: entries.map((e, i) => ({
1099→      index: i + 1,
1100→      messageId: e.messageId,
1101→      messageType: e.messageType,
1102→      subject: e.subject,
1103→      read: !!(e.flags & MailCheckMask.READ),
1104→      expirationDays: e.expirationDays,
1105→      money: e.money,
1106→      itemCount: e.itemCount,
1107→    })),
1108→  });
1109→}
1110→
1111→export function formatMailRead(
1112→  entry: MailEntry,
1113→  sender: string,
1114→): string {
1115→  const age = formatMailAge(entry.expirationDays);
1116→  const lines = [`From: ${sender}`, `Subject: ${entry.subject}`, `Date: ${age} ago`];
1117→  if (entry.money > 0) {
1118→    const gold = Math.floor(entry.money / 10000);
1119→    const silver = Math.floor((entry.money % 10000) / 100);
1120→    const copper = entry.money % 100;
1121→    const parts: string[] = [];
1122→    if (gold > 0) parts.push(`${gold}g`);
1123→    if (silver > 0) parts.push(`${silver}s`);
1124→    if (copper > 0) parts.push(`${copper}c`);
1125→    lines.push(`Money: ${parts.join(" ")}`);
1126→  }
1127→  if (entry.itemCount > 0) {
1128→    lines.push(`Attachments: ${entry.itemCount} item(s)`);
1129→  }
1130→  lines.push("");
1131→  lines.push(entry.body || "(no message)");
1132→  return lines.join("\n");
1133→}
