1311→  return Number.isFinite(n) && n > 0 ? { type: "mail_read", index: n } : undefined;
1312→}
1313→case "MAIL_READ_JSON": {
1314→  const n = parseInt(rest, 10);
1315→  return Number.isFinite(n) && n > 0 ? { type: "mail_read_json", index: n } : undefined;
1316→}
1317→case "MAIL_SEND": {
1318→  const parsed = parseCommand(`/mail send ${rest}`);
1319→  if (parsed.type === "mail-send") {
1320→    return { type: "mail_send", target: parsed.target, subject: parsed.subject, body: parsed.body };
1321→  }
1322→  return undefined;
1323→}
1324→case "MAIL_DELETE": {
1325→  const n = parseInt(rest, 10);
1326→  return Number.isFinite(n) && n > 0 ? { type: "mail_delete", index: n } : undefined;
1327→}
