1345→```typescript
1346→case "mail_list": {
1347→  if (!handle.getMailboxGuid()) {
1348→    writeLines(socket, ["ERR No mailbox open"]);
1349→    return false;
1350→  }
1351→  const entries = await handle.requestMailList();
1352→  writeLines(socket, formatMailList(entries, handle.getNameCache()).split("\n"));
1353→  return false;
1354→}
1355→case "mail_list_json": {
1356→  if (!handle.getMailboxGuid()) {
1357→    writeLines(socket, [JSON.stringify({ type: "MAIL_LIST", error: "No mailbox open" })]);
1358→    return false;
1359→  }
1360→  const entries = await handle.requestMailList();
1361→  writeLines(socket, [formatMailListJson(entries)]);
1362→  return false;
1363→}
1364→case "mail_read": {
1365→  if (!handle.getMailboxGuid()) {
1366→    writeLines(socket, ["ERR No mailbox open"]);
1367→    return false;
1368→  }
1369→  const cache = handle.getMailCache();
1370→  const entry = cache[cmd.index - 1];
1371→  if (!entry) {
1372→    writeLines(socket, [`ERR No mail #${cmd.index}`]);
1373→    return false;
1374→  }
1375→  let sender = "Unknown";
1376→  if (entry.senderGuid !== undefined) {
1377→    const guidLow = Number(entry.senderGuid & 0xffffffffn);
1378→    sender = handle.getNameCache().get(guidLow) ?? "Unknown";
1379→  }
1380→  handle.markMailAsRead(entry.messageId);
1381→  writeLines(socket, formatMailRead(entry, sender).split("\n"));
1382→  return false;
1383→}
1384→case "mail_read_json": {
1385→  if (!handle.getMailboxGuid()) {
1386→    writeLines(socket, [JSON.stringify({ type: "MAIL_READ", error: "No mailbox open" })]);
1387→    return false;
1388→  }
1389→  const cache = handle.getMailCache();
1390→  const entry = cache[cmd.index - 1];
1391→  if (!entry) {
1392→    writeLines(socket, [JSON.stringify({ type: "MAIL_READ", error: `No mail #${cmd.index}` })]);
1393→    return false;
1394→  }
1395→  let sender = "Unknown";
1396→  if (entry.senderGuid !== undefined) {
1397→    const guidLow = Number(entry.senderGuid & 0xffffffffn);
1398→    sender = handle.getNameCache().get(guidLow) ?? "Unknown";
1399→  }
1400→  handle.markMailAsRead(entry.messageId);
1401→  writeLines(socket, [formatMailReadJson(entry, sender)]);
1402→  return false;
1403→}
1404→case "mail_send": {
1405→  if (!handle.getMailboxGuid()) {
1406→    writeLines(socket, ["ERR No mailbox open"]);
1407→    return false;
1408→  }
1409→  handle.sendMail(cmd.target, cmd.subject, cmd.body);
1410→  writeLines(socket, ["OK"]);
1411→  return false;
1412→}
1413→case "mail_delete": {
1414→  if (!handle.getMailboxGuid()) {
1415→    writeLines(socket, ["ERR No mailbox open"]);
1416→    return false;
1417→  }
1418→  const delCache = handle.getMailCache();
1419→  const delEntry = delCache[cmd.index - 1];
1420→  if (!delEntry) {
1421→    writeLines(socket, [`ERR No mail #${cmd.index}`]);
1422→    return false;
1423→  }
1424→  handle.deleteMail(delEntry.messageId);
1425→  writeLines(socket, ["OK"]);
1426→  return false;
1427→}
