124→   124→   124→    expirationTime?: number;
125→   125→   125→    money?: number;
126→   126→   126→    itemCount?: number;
127→   127→   127→  },
128→   128→   128→) {
129→   129→   129→  const sizePos = w.offset;
130→   130→   130→  w.uint16LE(0);
131→   131→   131→  const startPos = w.offset;
132→   132→   132→  w.uint32LE(opts.messageId);
133→   133→   133→  w.uint8(MailMessageType.NORMAL);
134→   134→   134→  w.uint64LE(opts.senderGuid);
135→   135→   135→  w.uint32LE(0);
136→   136→   136→  w.uint32LE(0);
137→   137→   137→  w.uint32LE(41);
138→   138→   138→  w.uint32LE(opts.money ?? 0);
139→   139→   139→  w.uint32LE(opts.flags ?? MailCheckMask.HAS_BODY);
140→   140→   140→  w.floatLE(opts.expirationTime ?? 1.0);
141→   141→   141→  w.uint32LE(0);
142→   142→   142→  w.cString(opts.subject);
143→   143→   143→  w.cString(opts.body);
144→   144→   144→  w.uint8(opts.itemCount ?? 0);
145→   145→   145→  const endPos = w.offset;
146→   146→   146→  const buf = w.finish();
147→   147→   147→  const view = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
148→   148→   148→  view.setUint16(sizePos, endPos - startPos, true);
149→   149→   149→  return new Uint8Array(buf);
150→   150→   150→}
