519→   519→export function parseMailListResult(r: PacketReader): MailListResult {
520→   520→  const totalCount = r.uint32LE();
521→   521→  const count = r.uint8();
522→   522→  const entries: MailEntry[] = [];
523→   523→  for (let i = 0; i < count; i++) {
524→   524→    const size = r.uint16LE();
525→   525→    const entryStart = r.offset;
526→   526→    const messageId = r.uint32LE();
527→   527→    const messageType = r.uint8();
528→   528→    let senderGuid: bigint | undefined;
529→   529→    let senderEntry: number | undefined;
530→   530→    if (messageType === MailMessageType.NORMAL) {
531→   531→      senderGuid = r.uint64LE();
532→   532→    } else {
533→   533→      senderEntry = r.uint32LE();
534→   534→    }
535→   535→    const cod = r.uint32LE();
536→   536→    r.uint32LE();
537→   537→    const stationery = r.uint32LE();
538→   538→    const money = r.uint32LE();
539→   539→    const flags = r.uint32LE();
540→   540→    const expirationDays = r.floatLE();
541→   541→    r.uint32LE();
542→   542→    const subject = r.cString();
543→   543→    const body = r.cString();
544→   544→    const itemCount = r.uint8();
545→   545→    const consumed = r.offset - entryStart;
546→   546→    if (consumed < size) r.skip(size - consumed);
547→   547→    entries.push({
548→   548→      messageId,
549→   549→      messageType,
550→   550→      senderGuid,
551→   551→      senderEntry,
552→   552→      cod,
553→   553→      stationery,
554→   554→      money,
555→   555→      flags,
556→   556→      expirationDays,
557→   557→      subject,
558→   558→      body,
559→   559→      itemCount,
560→   560→    });
561→   561→  }
562→   562→  return { totalCount, entries };
563→   563→}
