613→   613→  mailId: number,
614→   614→): Uint8Array {
615→   615→  const w = new PacketWriter();
616→   616→  w.uint64LE(mailboxGuid);
617→   617→  w.uint32LE(mailId);
618→   618→  return w.finish();
