947→   947→function parseMailSend(
948→   948→  input: string,
949→   949→): { type: "mail-send"; target: string; subject: string; body: string } | undefined {
950→   950→  const trimmed = input.trim();
951→   951→  if (!trimmed) return undefined;
952→   952→  const spaceIdx = trimmed.indexOf(" ");
953→   953→  if (spaceIdx === -1) return undefined;
954→   954→  const target = trimmed.slice(0, spaceIdx);
955→   955→  const afterTarget = trimmed.slice(spaceIdx + 1).trim();
956→   956→  if (!afterTarget.startsWith('"')) return undefined;
957→   957→  const endQuote = afterTarget.indexOf('"', 1);
958→   958→  if (endQuote === -1) return undefined;
959→   959→  const subject = afterTarget.slice(1, endQuote);
960→   960→  const body = afterTarget.slice(endQuote + 1).trim();
961→   961→  return { type: "mail-send", target, subject, body };
962→   962→}
